Date.now(); // \u5F53\u524D\u65F6\u95F4 \u65F6\u95F4\u6233
dayjs('1995-12-25'); // 1995-12-25
dayjs(Date.now() - 24 * 60 * 60 * 1000); // \u6628\u5929

// \u8FD4\u56DE\u4FEE\u6539\u540E\u7684\u503C \u672C\u8EAB\u4E5F\u4F1A\u88AB\u4FEE\u6539
dayjs().add(7, 'days'); // \u4E4B\u540E\u7684\u7B2C7\u5929
dayjs().subtract(1, 'months'); // \u4E0A\u4E2A\u6708
dayjs().startOf('months'); // \u83B7\u53D6\u4E00\u6708\u521D
dayjs().endOf('year'); // \u83B7\u53D6\u4E00\u5E74\u5E74\u672B

dayjs('2010-10-20').isBefore('2010-10-21'); // \u65E9\u4E8E
