let a = {};
let fn = function () {
  console.log(this);
};
fn.bind().bind(a)(); // => ?

// fn.bind().bind(a) \u7B49\u4E8E
// \u5D4C\u5957\u51FD\u6570\u7684\u8C03\u7528\u987A\u5E8F\u662F\u4ECE\u5916\u5230\u91CC
let fn2 = function fn1() {
  return function () {
    return fn.apply();
  }.apply(a);
};
fn2();

