// \u8FD9\u662F\u4E00\u4E2A\u6700\u57FA\u7840\u7684\u6590\u6CE2\u90A3\u5951\u6570\u5217
function fibonacci(n) {
  const fn = arguments.callee;
  if (n <= 1) return 1;
  return fn(n - 1) + fn(n - 2);
}
